class Solution:
    def maxSum(self, grid, limits, k):
        # independent re-derivation: explore how much budget to spend per row via
        # a small knapsack over rows, still only ever needing each row's sorted prefix
        n = len(grid)
        row_prefix = []
        for i in range(n):
            row = sorted(grid[i], reverse=True)[:limits[i]]
            prefix = [0]
            for v in row:
                prefix.append(prefix[-1] + v)
            row_prefix.append(prefix)
        # dp[b] = best sum using exactly b picks so far across processed rows
        dp = [float('-inf')] * (k + 1)
        dp[0] = 0
        for prefix in row_prefix:
            ndp = [float('-inf')] * (k + 1)
            maxtake = len(prefix) - 1
            for b in range(k + 1):
                if dp[b] == float('-inf'):
                    continue
                for t in range(0, min(maxtake, k - b) + 1):
                    val = dp[b] + prefix[t]
                    if val > ndp[b + t]:
                        ndp[b + t] = val
            dp = ndp
        return max(dp)

