class Solution:
    def maxSum(self, grid, limits, k):
        candidates = []
        for row, lim in zip(grid, limits):
            top = sorted(row, reverse=True)[:lim]
            candidates.extend(top)
        candidates.sort(reverse=True)
        return sum(candidates[:k])

